{"code":"import json, re
# var_call_1io1Ln1MpXYuyOoPruPFfSdO contains the filepath to the JSON results from the earlier query
path = var_call_1io1Ln1MpXYuyOoPruPFfSdO
with open(path, 'r', encoding='utf-8') as f:
    records = json.load(f)
pubnums = set()
patterns = [r'pub(?:lication)?\. number\s*([A-Z0-9-]+)', r'publication number\s*([A-Z0-9-]+)', r'pub\. number\s*([A-Z0-9-]+)', r'publication number\s*([A-Z0-9-]+)']
for r in records:
    pi = r.get('Patents_info','')
    for pat in patterns:
        for m in re.finditer(pat, pi, flags=re.IGNORECASE):
            pubnums.add(m.group(1))
# fallback: also look for patterns like "with pub. number X" or "with publication number X"
for r in records:
    pi = r.get('Patents_info','')
    m = re.search(r'with (?:pub(?:lication)?\. number|publication number|pub\. number)\s*([A-Z0-9-]+)', pi, flags=re.IGNORECASE)
    if m:
        pubnums.add(m.group(1))
# As an extra, look for uppercase token sequences with hyphens that look like publication numbers
for r in records:
    pi = r.get('Patents_info','')
    toks = re.findall(r'\b[A-Z]{2,}-[A-Z0-9-]+\b', pi)
    for t in toks:
        if any(ch.isdigit() for ch in t):
            pubnums.add(t)

pubnums = sorted(pubnums)
# Output as JSON-serializable string
out = json.dumps({'publication_numbers': pubnums})
print("__RESULT__:")
print(out)"}

{"code":"import json, re
# Load univ cal publication numbers from var_call_Y9yJJI0JekmBPYqFML5O5pfw
univ_pubs = set(json.loads(var_call_Y9yJJI0JekmBPYqFML5O5pfw)['publication_numbers'])
# Load non-UNIV records from file path var_call_q6uBgUJjdgKLjIj9qxzqBT1n
path = var_call_q6uBgUJjdgKLjIj9qxzqBT1n
with open(path, 'r', encoding='utf-8') as f:
    records = json.load(f)

results = []
for r in records:
    cit_str = r.get('citation')
    if not cit_str:
        continue
    try:
        citations = json.loads(cit_str)
    except Exception:
        # try to extract publication numbers via regex
        citations = []
    matched = False
    for c in citations:
        pubnum = c.get('publication_number','') if isinstance(c, dict) else ''
        if pubnum in univ_pubs:
            matched = True
            break
    if not matched:
        continue
    # extract assignee from Patents_info
    pi = r.get('Patents_info','')
    assignee = None
    m = re.match(r'^(.*?) holds', pi)
    if m:
        assignee = m.group(1).strip()
    if not assignee:
        m = re.search(r'is assigned to ([A-Z0-9 &.,\'-]+)', pi)
        if m:
            assignee = m.group(1).strip()
    if not assignee:
        m = re.search(r'owned by ([A-Z0-9 &.,\'-]+)', pi)
        if m:
            assignee = m.group(1).strip()
    if not assignee:
        # fallback: take leading token up to first comma or 'the'
        assignee = pi.split(' holds')[0].strip()
    if not assignee:
        continue
    assignee = assignee.strip(' ,.')
    if 'UNIV CALIFORNIA' in assignee.upper():
        continue
    # parse cpc field
    cpc_str = r.get('cpc')
    codes = []
    if cpc_str:
        try:
            cpcs = json.loads(cpc_str)
            for entry in cpcs:
                if isinstance(entry, dict):
                    if entry.get('first'):
                        codes.append(entry.get('code'))
            if not codes and len(cpcs)>0:
                # fallback to first code
                codes.append(cpcs[0].get('code'))
        except Exception:
            pass
    if not codes:
        continue
    for code in codes:
        results.append({'assignee': assignee, 'cpc_code': code})
# deduplicate
unique = {}
for r in results:
    a = r['assignee']
    c = r['cpc_code']
    unique.setdefault(a, set()).add(c)
# prepare output lists
pairs = []
all_codes = set()
for a, codes in unique.items():
    for c in codes:
        pairs.append({'assignee': a, 'cpc_code': c})
        all_codes.add(c)
out = {'pairs': pairs, 'cpc_codes': sorted(all_codes)}
print('__RESULT__:')
print(json.dumps(out))"}

