patterns = [r'pub(?:lication)?\. number\s*([A-Z0-9-]+)', r'publication number\s*([A-Z0-9-]+)', r'pub\. number\s*([A-Z0-9-]+)', r'publication number\s*([A-Z0-9-]+)']
for r in records:
